evaluators.evaluation_logic:
const checkpoints = [];

var slots = JSON.parse(localStorage.getItem('appointment_slots') || '[]');
var requests = JSON.parse(localStorage.getItem('appointment_requests') || '[]');

// Find all morning new-patient slots at Main Clinic – Downtown
var candidateSlots = slots.filter(function (s) {
  return s.location_id === 'main_clinic_downtown' &&
    s.appointment_type === 'new_patient' &&
    s.is_morning_slot === true;
});

candidateSlots.sort(function (a, b) {
  return new Date(a.start_datetime).getTime() - new Date(b.start_datetime).getTime();
});

var earliestSlot = candidateSlots.length > 0 ? candidateSlots[0] : null;
var earliestSlotId = earliestSlot ? earliestSlot.id : null;

function isType1Reason(r) {
  var label = (r.reason_for_visit_label || '').toLowerCase();
  return r.reason_for_visit_code === 'type_1_diabetes' || label.indexOf('type 1 diabetes') !== -1;
}

// All submitted new-patient, Type 1 diabetes requests at Main Clinic – Downtown
var mainType1Requests = requests.filter(function (r) {
  return r.appointment_type === 'new_patient' &&
    r.location_id === 'main_clinic_downtown' &&
    isType1Reason(r) &&
    r.status === 'submitted';
});

// CP1 (0.4): Submitted a new-patient Type 1 diabetes request at Main Clinic – Downtown
checkpoints.push({ passed: mainType1Requests.length > 0, weight: 0.4 });

// CP2 (0.6): That request uses the earliest morning new-patient slot at Main Clinic – Downtown
var earliestRequests = (earliestSlotId && mainType1Requests.length > 0)
  ? mainType1Requests.filter(function (r) { return r.appointment_slot_id === earliestSlotId; })
  : [];

checkpoints.push({ passed: !!earliestSlotId && earliestRequests.length > 0, weight: 0.6 });

return checkpoints.reduce(function (sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

var selectedDoctorId = localStorage.getItem('task2_selectedDoctorId');
var doctors = JSON.parse(localStorage.getItem('doctors') || '[]');
var conditions = JSON.parse(localStorage.getItem('conditions') || '[]');

// Find the thyroid disorders condition id
var thyroidCondition = null;
for (var i = 0; i < conditions.length; i++) {
  var c = conditions[i];
  var nameLower = (c.name || '').toLowerCase();
  if (c.slug === 'thyroid_disorders' || nameLower.indexOf('thyroid') !== -1) {
    thyroidCondition = c;
    break;
  }
}

var thyroidConditionId = thyroidCondition ? thyroidCondition.id : null;

// All qualifying doctors: treat thyroid, speak Spanish, ≥10 years experience
var qualifyingDoctors = doctors.filter(function (d) {
  var treatsThyroid = thyroidConditionId && Array.isArray(d.conditions_treated_ids) && d.conditions_treated_ids.indexOf(thyroidConditionId) !== -1;
  var langs = Array.isArray(d.languages_spoken) ? d.languages_spoken.map(function (x) { return String(x).toLowerCase(); }) : [];
  var speaksSpanish = langs.indexOf('spanish') !== -1;
  var experienced = typeof d.years_of_experience === 'number' && d.years_of_experience >= 10;
  return treatsThyroid && speaksSpanish && experienced;
});

qualifyingDoctors.sort(function (a, b) {
  var la = (a.last_name || '').toLowerCase();
  var lb = (b.last_name || '').toLowerCase();
  if (la < lb) return -1;
  if (la > lb) return 1;
  return 0;
});

var firstQualifying = qualifyingDoctors.length > 0 ? qualifyingDoctors[0] : null;
var selectedDoctor = doctors.find(function (d) { return d.id === selectedDoctorId; }) || null;

// Helper to check if a doctor is qualifying
function isQualifyingDoctor(d) {
  if (!d || !thyroidConditionId) return false;
  var treatsThyroid = Array.isArray(d.conditions_treated_ids) && d.conditions_treated_ids.indexOf(thyroidConditionId) !== -1;
  var langs = Array.isArray(d.languages_spoken) ? d.languages_spoken.map(function (x) { return String(x).toLowerCase(); }) : [];
  var speaksSpanish = langs.indexOf('spanish') !== -1;
  var experienced = typeof d.years_of_experience === 'number' && d.years_of_experience >= 10;
  return treatsThyroid && speaksSpanish && experienced;
}

// CP1 (0.5): Selected doctor is a qualifying Spanish-speaking thyroid specialist with ≥10 years experience
var cp1Passed = isQualifyingDoctor(selectedDoctor);
checkpoints.push({ passed: cp1Passed, weight: 0.5 });

// CP2 (0.5): Selected doctor is the FIRST qualifying doctor in the list
var cp2Passed = !!firstQualifying && !!selectedDoctor && firstQualifying.id === selectedDoctor.id && isQualifyingDoctor(selectedDoctor);
checkpoints.push({ passed: cp2Passed, weight: 0.5 });

return checkpoints.reduce(function (sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

var events = JSON.parse(localStorage.getItem('class_events') || '[]');
var registrations = JSON.parse(localStorage.getItem('class_registrations') || '[]');

// Topic: Insulin Pump Education; time at or after 17:00; registration open
var eligibleEvents = events.filter(function (e) {
  if ((e.topic || '') !== 'Insulin Pump Education') return false;
  if (e.registration_open !== true) return false;
  var start = new Date(e.start_datetime);
  if (!e.start_datetime || isNaN(start.getTime())) return false;
  var hours = start.getUTCHours();
  var minutes = start.getUTCMinutes();
  var timeMinutes = hours * 60 + minutes;
  // 17:00 or later
  return timeMinutes >= 17 * 60;
});

eligibleEvents.sort(function (a, b) {
  return new Date(a.start_datetime).getTime() - new Date(b.start_datetime).getTime();
});

var earliestEligible = eligibleEvents.length > 0 ? eligibleEvents[0] : null;

// Registrations tied to any eligible Insulin Pump Education class
var registrationsForEligibleEvents = registrations.filter(function (r) {
  return eligibleEvents.some(function (e) { return e.id === r.class_event_id; }) &&
    r.status === 'submitted';
});

// CP1 (0.4): Registered for any qualifying insulin pump education class (5:00 PM or later, registration open)
checkpoints.push({ passed: registrationsForEligibleEvents.length > 0, weight: 0.4 });

// CP2 (0.6): Registered for the earliest such class, with exactly 2 attendees (one child + one parent)
var earliestRegistration = (earliestEligible && registrations.length > 0)
  ? registrations.find(function (r) { return r.class_event_id === earliestEligible.id && r.status === 'submitted'; })
  : null;

var cp2Passed = !!earliestEligible && !!earliestRegistration && (typeof earliestRegistration.attendee_count === 'number' ? earliestRegistration.attendee_count >= 2 : true);
checkpoints.push({ passed: cp2Passed, weight: 0.6 });

return checkpoints.reduce(function (sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

var articles = JSON.parse(localStorage.getItem('education_articles') || '[]');
var savedLists = JSON.parse(localStorage.getItem('saved_articles') || '[]');

// Determine the default saved list
var savedList = null;
for (var i = 0; i < savedLists.length; i++) {
  if (savedLists[i].id === 'default') {
    savedList = savedLists[i];
    break;
  }
}

var savedIds = savedList && Array.isArray(savedList.article_ids) ? savedList.article_ids : [];

// Articles about Growth Hormone Deficiency, easy reading level, published within last 2 years
// Baseline date is 2026-03-03, so last 2 years start at 2024-03-03
var minDate = new Date('2024-03-03T00:00:00Z').getTime();

var qualifyingArticles = articles.filter(function (a) {
  if ((a.topic || '') !== 'Growth Hormone Deficiency') return false;
  if (a.reading_level !== 'easy') return false;
  if (!a.publication_date) return false;
  var pub = new Date(a.publication_date).getTime();
  if (isNaN(pub)) return false;
  return pub >= minDate;
});

// Sort by publication_date descending (newest first), matching searchEducationArticles
qualifyingArticles.sort(function (a, b) {
  var da = new Date(a.publication_date).getTime();
  var db = new Date(b.publication_date).getTime();
  return db - da;
});

var topTwo = qualifyingArticles.slice(0, 2);
var topTwoIds = topTwo.map(function (a) { return a.id; });

// Count how many of the top two qualifying articles were saved
var savedTopTwoCount = topTwoIds.filter(function (id) { return savedIds.indexOf(id) !== -1; }).length;

// CP1 (0.4): Saved at least one of the top two qualifying recent, easy GHD articles
checkpoints.push({ passed: savedTopTwoCount >= 1, weight: 0.4 });

// CP2 (0.6): Saved both of the top two qualifying recent, easy GHD articles
checkpoints.push({ passed: savedTopTwoCount >= 2, weight: 0.6 });

return checkpoints.reduce(function (sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

var calcId = localStorage.getItem('task5_printViewCalculationId');
var calculations = JSON.parse(localStorage.getItem('growth_calculations') || '[]');
var calc = calculations.find(function (c) { return c.id === calcId; }) || null;

// CP1 (0.4): Print view opened for a school-age girl (female, age in years between ~5 and 12)
var cp1Passed = !!calc &&
  calc.child_sex === 'female' &&
  calc.child_age_unit === 'years' &&
  typeof calc.child_age_value === 'number' &&
  calc.child_age_value >= 5 && calc.child_age_value <= 12;
checkpoints.push({ passed: cp1Passed, weight: 0.4 });

// CP2 (0.3): Same print-view calculation used height in centimeters with value 120
var cp2Passed = !!calc &&
  calc.child_sex === 'female' &&
  calc.height_unit === 'cm' &&
  typeof calc.height_value === 'number' &&
  calc.height_value === 120;
checkpoints.push({ passed: cp2Passed, weight: 0.3 });

// CP3 (0.3): Same print-view calculation used weight in kilograms with value 25
var cp3Passed = !!calc &&
  calc.child_sex === 'female' &&
  calc.weight_unit === 'kg' &&
  typeof calc.weight_value === 'number' &&
  calc.weight_value === 25;
checkpoints.push({ passed: cp3Passed, weight: 0.3 });

return checkpoints.reduce(function (sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

var plans = JSON.parse(localStorage.getItem('insurance_plans') || '[]');
var questions = JSON.parse(localStorage.getItem('billing_questions') || '[]');

// Identify silver-tier HMO plans that require referrals by name and flags
var qualifyingPlans = plans.filter(function (p) {
  var nameLower = (p.name || '').toLowerCase();
  var isSilver = nameLower.indexOf('silver') !== -1;
  var isHmo = nameLower.indexOf('hmo') !== -1;
  var requiresReferral = p.referral_required === true;
  return isSilver && isHmo && requiresReferral;
});

var qualifyingPlanIds = qualifyingPlans.map(function (p) { return p.id; });

// Billing questions linked to any qualifying silver HMO plan
var questionsForPlan = questions.filter(function (q) {
  return q.insurance_plan_id && qualifyingPlanIds.indexOf(q.insurance_plan_id) !== -1;
});

// CP1 (0.4): Submitted a billing question associated with a qualifying silver-tier HMO plan that requires referrals
checkpoints.push({ passed: questionsForPlan.length > 0, weight: 0.4 });

// For CP2 and CP3, also require message content about co-pay and endocrinology
var copayAndEndoQuestions = questionsForPlan.filter(function (q) {
  var msg = (q.message || '').toLowerCase();
  var mentionsCopay = msg.indexOf('co-pay') !== -1 || msg.indexOf('copay') !== -1 || msg.indexOf('co pay') !== -1;
  var mentionsEndo = msg.indexOf('endocrinolog') !== -1; // matches 'endocrinology' / 'endocrinologist'
  return mentionsCopay && mentionsEndo;
});

// CP2 (0.3): Billing question message explicitly asks about specialist co-pay for (pediatric) endocrinology
checkpoints.push({ passed: copayAndEndoQuestions.length > 0, weight: 0.3 });

// CP3 (0.3): Billing question message references the plan's listed specialist co-pay amount
var cp3Passed = false;
if (copayAndEndoQuestions.length > 0 && qualifyingPlans.length > 0) {
  // Assume any qualifying plan's copay amount is what should be referenced
  for (var i = 0; i < copayAndEndoQuestions.length && !cp3Passed; i++) {
    var q = copayAndEndoQuestions[i];
    var plan = qualifyingPlans.find(function (p) { return p.id === q.insurance_plan_id; });
    if (!plan || typeof plan.specialist_copay_amount !== 'number') continue;
    var amountStr = String(plan.specialist_copay_amount);
    var msgLower = (q.message || '').toLowerCase();
    if (msgLower.indexOf(amountStr) !== -1) {
      cp3Passed = true;
      break;
    }
  }
}

checkpoints.push({ passed: cp3Passed, weight: 0.3 });

return checkpoints.reduce(function (sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

var pharmacies = JSON.parse(localStorage.getItem('pharmacies') || '[]');
var slots = JSON.parse(localStorage.getItem('pharmacy_pickup_slots') || '[]');
var refills = JSON.parse(localStorage.getItem('prescription_refill_requests') || '[]');

// Find first pharmacy within 5 miles of ZIP 10027 (based on postal_code match and distance)
var nearby = pharmacies.filter(function (p) {
  if (p.postal_code !== '10027') return false;
  if (typeof p.distance_miles === 'number' && p.distance_miles > 5) return false;
  return true;
});

nearby.sort(function (a, b) {
  var da = typeof a.distance_miles === 'number' ? a.distance_miles : Number.POSITIVE_INFINITY;
  var db = typeof b.distance_miles === 'number' ? b.distance_miles : Number.POSITIVE_INFINITY;
  return da - db;
});

var firstPharmacy = nearby.length > 0 ? nearby[0] : null;
var firstPharmacyId = firstPharmacy ? firstPharmacy.id : null;

// Today is the baseline date 2026-03-03
var todayDateStr = '2026-03-03';

function extractDatePart(iso) {
  if (!iso) return null;
  var d = new Date(iso);
  if (isNaN(d.getTime())) return null;
  return d.toISOString().slice(0, 10);
}

// Earliest available slot at or after 16:00 today for that pharmacy
var availableSlots = slots.filter(function (s) {
  if (!firstPharmacyId || s.pharmacy_id !== firstPharmacyId) return false;
  if (s.status !== 'available') return false;
  if (extractDatePart(s.start_datetime) !== todayDateStr) return false;
  var start = new Date(s.start_datetime);
  if (isNaN(start.getTime())) return false;
  var minutesSinceMidnight = start.getUTCHours() * 60 + start.getUTCMinutes();
  return minutesSinceMidnight >= 16 * 60; // 4:00 PM or later
});

availableSlots.sort(function (a, b) {
  return new Date(a.start_datetime).getTime() - new Date(b.start_datetime).getTime();
});

var earliestSlot = availableSlots.length > 0 ? availableSlots[0] : null;
var earliestSlotId = earliestSlot ? earliestSlot.id : null;

// Helper: does refill match levothyroxine 50 mcg tablet with qty 30 for existing patient?
function isLevothyroxine50TabletRefill(r) {
  if (!r) return false;
  var medName = (r.medication_name || '').toLowerCase();
  var isExisting = r.patient_type === 'existing_patient';
  var mentionsLevo = medName.indexOf('levothyroxine') !== -1;
  var mentions50 = medName.indexOf('50 mcg') !== -1 || (r.medication_strength === '50 mcg');
  var isTablet = (r.medication_form === 'tablet') || medName.indexOf('tablet') !== -1;
  var qtyOk = typeof r.quantity === 'number' && r.quantity >= 30;
  return isExisting && mentionsLevo && mentions50 && isTablet && qtyOk;
}

// CP1 (0.4): Submitted a refill request for an existing patient for levothyroxine 50 mcg tablets with quantity ≥ 30
var levothyroxineRefills = refills.filter(isLevothyroxine50TabletRefill);
checkpoints.push({ passed: levothyroxineRefills.length > 0, weight: 0.4 });

// CP2 (0.4): Such a refill request uses the nearest pharmacy and earliest ≥4 PM pickup slot today
var correctLocationTimeRefills = levothyroxineRefills.filter(function (r) {
  return r.pharmacy_id === firstPharmacyId &&
    r.pickup_slot_id &&
    r.pickup_slot_id === earliestSlotId;
});
checkpoints.push({ passed: !!firstPharmacyId && !!earliestSlotId && correctLocationTimeRefills.length > 0, weight: 0.4 });

// CP3 (0.2): That request includes parent/guardian contact details (phone and email, plus guardian name)
var cp3Passed = false;
if (correctLocationTimeRefills.length > 0) {
  for (var i = 0; i < correctLocationTimeRefills.length; i++) {
    var r = correctLocationTimeRefills[i];
    if (r.contact_phone && r.contact_email && r.parent_guardian_name) {
      cp3Passed = true;
      break;
    }
  }
}
checkpoints.push({ passed: cp3Passed, weight: 0.2 });

return checkpoints.reduce(function (sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

var forms = JSON.parse(localStorage.getItem('patient_forms') || '[]');
var questionnaires = JSON.parse(localStorage.getItem('new_patient_questionnaires') || '[]');

// Find the endocrine intake form id (expected 'new_patient_endocrine_intake')
var intakeForm = forms.find(function (f) { return f.id === 'new_patient_endocrine_intake'; }) || null;
var intakeFormId = intakeForm ? intakeForm.id : 'new_patient_endocrine_intake';

// Submissions tied to the endocrine intake form
var intakeSubmissions = questionnaires.filter(function (q) {
  return q.patient_form_id === intakeFormId && q.status === 'submitted';
});

// Find a submission where the primary concern is early puberty
function isEarlyPubertyConcern(q) {
  if (!q) return false;
  if (q.primary_concern_code === 'early_puberty') return true;
  var text = (q.primary_concern_text || '').toLowerCase();
  return text.indexOf('early puberty') !== -1 || text.indexOf('precocious') !== -1;
}

var qualifyingSubmission = intakeSubmissions.find(isEarlyPubertyConcern) || null;

// CP1 (0.4): Submitted endocrine intake questionnaire with early puberty as primary concern
checkpoints.push({ passed: !!qualifyingSubmission, weight: 0.4 });

// CP2 (0.3): That submission includes required demographic and contact fields plus an upcoming visit date
var cp2Passed = false;
if (qualifyingSubmission) {
  var q = qualifyingSubmission;
  var hasChildName = !!q.child_name;
  var hasDob = !!q.child_date_of_birth;
  var hasSex = !!q.child_sex;
  var hasParentName = !!q.parent_guardian_name;
  var hasPhone = !!q.parent_guardian_phone;
  var hasEmail = !!q.parent_guardian_email;
  var hasVisitDate = !!q.upcoming_visit_date;
  cp2Passed = hasChildName && hasDob && hasSex && hasParentName && hasPhone && hasEmail && hasVisitDate;
}
checkpoints.push({ passed: cp2Passed, weight: 0.3 });

// CP3 (0.3): That submission answers mandatory background questions (previous visits and allergies)
var cp3Passed = false;
if (qualifyingSubmission) {
  var q2 = qualifyingSubmission;
  var hasPrevVisits = typeof q2.has_previous_endocrine_visits === 'boolean';
  var hasAllergiesDesc = typeof q2.allergies_description === 'string' && q2.allergies_description.length >= 0;
  cp3Passed = hasPrevVisits && hasAllergiesDesc;
}
checkpoints.push({ passed: cp3Passed, weight: 0.3 });

return checkpoints.reduce(function (sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);
